content.code:
.grid-container {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 10px;
    padding: 10px;
}

.item {
    background-color: dodgerblue;
    color: white;
    padding: 20px;
    text-align: center;
}

.container {
    display: grid;
    grid-template-columns: 1fr 2fr 1fr;
    grid-template-rows: auto;
    gap: 15px;
}

.layout {
    display: grid;
    grid-template-columns: 200px 1fr;
    grid-template-rows: auto 1fr auto;
    gap: 10px;
}

.header {
    grid-column: 1 / 3;
}

.footer {
    grid-column: 1 / 3;
}
